function getPartiallyVisibleRange(range,viewportRect,intersectionThreshold=0,ignoreTrailingVisibility=true){const rangeRect=getNonZeroBoundingClientRect(range);const intersection=getIntersectionPercentage(viewportRect,rangeRect);if(intersection===0||intersection>=1){return null}const textNode=range.startContainer;const startOffset=range.startOffset;const endOffset=range.endOffset;let firstVisibleIndex=-1;let lastVisibleIndex=-1;const loopRange=document.createRange();for(let i=startOffset;i<endOffset;i++){loopRange.setStart(textNode,i);loopRange.setEnd(textNode,i+1);const charRect=getNonZeroBoundingClientRect(loopRange);if(charRect.width===0&&charRect.height===0)continue;const intersection=getIntersectionPercentage(viewportRect,charRect);const isVisible=intersectionThreshold>0?intersection>=intersectionThreshold:intersection>0;if(isVisible){if(firstVisibleIndex===-1){firstVisibleIndex=i}lastVisibleIndex=i;if(ignoreTrailingVisibility){break}}}if(firstVisibleIndex!==-1){const resultRange=document.createRange();resultRange.setStart(textNode,firstVisibleIndex);const finalEndOffset=ignoreTrailingVisibility?range.endOffset:lastVisibleIndex+1;resultRange.setEnd(textNode,finalEndOffset);return resultRange}return null}function getTextStartPositionFromRange(range){let position=0;const clientRects=Array.from(range.getClientRects()).filter(rect=>rect.width>0);if(clientRects.length===0){return position}const rangeRect=viewportRectToDocumentRect(clientRects[0]);if(isScrollMode()){const scrollHeight=document.scrollingElement.scrollHeight;if(scrollHeight>0){position=Math.min(1,Math.max(0,rangeRect.top/scrollHeight))}}else{const scrollWidth=document.scrollingElement.scrollWidth;if(scrollWidth>0){const viewportRect=getViewportRect();const columnCount=getColumnCount();const clientWidth=columnCount>1?viewportRect.width/columnCount:viewportRect.width;const fullPageWidth=clientWidth>0?Math.floor(rangeRect.left/clientWidth)*clientWidth:0;const topOffset=viewportRect.height>0?rangeRect.top/viewportRect.height:0;const positionOffset=Math.min(1,clientWidth/scrollWidth)*topOffset;position=Math.min(1,Math.max(0,fullPageWidth/scrollWidth+positionOffset))}}return position}